if (hasRealData) {
  // ✅ 情況 A：Google Sheets 有找到資料！代表「可以刪除」
  // 使用展開語法 (...) 繼承 originalData，並額外塞入試算表的 row_number
  return [{
    json: {
      ...originalData,
      row_number: sheetResults[0].json.row_number, // 抓取要刪除的行號，給下一個 Delete 節點用
