            "wrap": true,
            "color": "#2c3e50",
            "size": "sm",
            "weight": "bold",
            "flex": 5
          },
          {
            "type": "text",
            "text": "➕", 
            "size": "xs",
            "color": "#3498db",
            "align": "end",
            "flex": 1
          }
        ]
      });
    }
  }
}

