  const dateA = padZero(a.json.日期);
  const dateB = padZero(b.json.日期);
  const timeA = padZero(a.json.時間);
  const timeB = padZero(b.json.時間);

  // 組合起來會變成像 "04/03 09:00" 這種非常標準的格式
  const dateTimeA = `${dateA} ${timeA}`;
  const dateTimeB = `${dateB} ${timeB}`;

  // 這樣字串比對就 100% 不會因為位數不同而排錯了！
  return dateTimeA.localeCompare(dateTimeB);
});
// ==========================================

