    const data = item.json;
    if (data.日期) {
      const displayDate = padZero(data.日期);
      const displayTime = padZero(data.時間);
      const displayType = data.類型 || ""; // 🌟 新增抓取類型
      const displayTitle = data.主題名稱 || ""; 

      // 🌟 依照新順序：日期 -> 時間 -> 類型 -> 主題
