for (const item of items) {
  const data = item.json;
  const eventDate = parseDate(data.日期);

  if (eventDate && eventDate >= now && eventDate <= sevenDaysLater) {
    upcomingItems.push(data);
  }
}

// 🌟 【修正 1】如果 7 天內沒行程，直接 return 空，讓 Webhook 不會噴發
if (upcomingItems.length === 0) {
  return []; 
}

