  const dateA = padZero(a.日期);
  const dateB = padZero(b.日期);
  const timeA = padZero(a.時間);
  const timeB = padZero(b.時間);
  return `${dateA} ${timeA}`.localeCompare(`${dateB} ${timeB}`);
