      { "type": "text", "text": fullTitle, "wrap": true, "color": "#2c3e50", "size": "sm", "weight": "bold", "flex": 6 }
    ]
  };
});
const targetGroupId = upcomingItems[0]["群組ID"] || "你的預設ID";
